128	function detectCollisions(actions: DeployAction[]): PlanWarning[] {
129	  const seen = new Map<string, { skill: string; agent: AgentId }>();
130	  const warnings: PlanWarning[] = [];
131	  for (const action of actions) {
132	    const prev = seen.get(action.target);
133	    if (prev) {
134	      warnings.push({
135	        kind: "collision",
136	        message: `Skill "${action.skill}" for agent "${action.agent}" and skill "${prev.skill}" for agent "${prev.agent}" both resolve to the same target: ${action.target}`,
137	      });
138	    } else {
139	      seen.set(action.target, { skill: action.skill, agent: action.agent });
140	    }
141	  }
142	  return warnings;
143	}
144	
145	function detectAmbiguities(detectedAgents: AgentId[]): PlanWarning[] {
146	  const warnings: PlanWarning[] = [];
147	  if (
148	    detectedAgents.includes("gemini-cli") &&
149	    detectedAgents.includes("antigravity")
150	  ) {
151	    warnings.push({
152	      kind: "ambiguity",
153	      message:
154	        'Both "gemini-cli" and "antigravity" share the ~/.gemini/ base directory. antigravity skill support is implementation-only. Verify that deployed skill paths do not conflict.',
155	    });
156	  }
157	  return warnings;
158	}
