160	async function planSkillDirActions(
161	  manifest: Manifest,
162	  sourceDir: string,
163	  resolvedSourceDir: string,
164	  realRoot: string,
165	  detectedAgents: AgentId[],
166	  home: string,
167	): Promise<SkillDirDeployAction[]> {
168	  const method = getDeployMethod();
169	  const actions: SkillDirDeployAction[] = [];
170	  for (const skill of manifest.skills) {
171	    const source = path.resolve(sourceDir, skill.path);
172	    await validateSourcePath(source, skill.path, resolvedSourceDir, realRoot);
173	    await validateSkillContract(source, skill.path);
174	    for (const agentId of skill.agents) {
175	      if (!detectedAgents.includes(agentId)) continue;
176	      const agent = AGENT_REGISTRY_BY_ID[agentId];
177	      if (!agent) continue;
178	      actions.push({
179	        kind: "skill-dir",
180	        skill: skill.name,
181	        agent: agentId,
182	        source,
183	        target: resolveAgentSkillPath(agent, skill.name, home),
184	        method,
185	        confidence: agent.provenance.skills,
186	      });
187	    }
188	  }
189	  return actions;
190	}
