251	export async function planDeploy(
252	  manifest: Manifest,
253	  sourceDir: string,
254	  detectedAgents: AgentId[],
255	  home: string,
256	): Promise<{ actions: DeployAction[]; warnings: PlanWarning[] }> {
257	  const resolvedSourceDir = path.resolve(sourceDir);
258	  let realRoot: string;
259	  try {
260	    realRoot = await realpath(resolvedSourceDir);
261	  } catch {
262	    realRoot = resolvedSourceDir;
263	  }
264	
265	  const actions: DeployAction[] = [
266	    ...(await planSkillDirActions(
267	      manifest,
268	      sourceDir,
269	      resolvedSourceDir,
270	      realRoot,
271	      detectedAgents,
272	      home,
273	    )),
274	    ...(await planFileWriteActions(
275	      manifest,
276	      sourceDir,
277	      resolvedSourceDir,
278	      realRoot,
279	      detectedAgents,
280	      home,
281	    )),
282	    ...planConfigPatchActions(manifest, detectedAgents, home),
283	  ];
284	
285	  const warnings: PlanWarning[] = [
286	    ...detectAmbiguities(detectedAgents),
287	    ...detectCollisions(actions),
288	  ];
289	
290	  return { actions, warnings };
291	}
