293	export async function executeDeploy(
294	  actions: DeployAction[],
295	  dryRun: boolean,
296	  verbose: boolean,
297	  home: string,
298	): Promise<{
299	  succeeded: number;
300	  failed: Array<{ action: DeployAction; error: string }>;
301	  planned: PlannedChange[];
302	}> {
303	  let succeeded = 0;
304	  const failed: Array<{ action: DeployAction; error: string }> = [];
305	  const planned: PlannedChange[] = [];
306	
307	  for (const action of actions) {
308	    switch (action.kind) {
309	      case "skill-dir": {
310	        const result = await deploySkillDir(
311	          action,
312	          dryRun,
313	          verbose,
314	          home,
315	          planned,
316	        );
317	        if (result.error === null) {
318	          succeeded++;
319	        } else {
320	          failed.push({ action, error: result.error });
321	        }
322	        break;
323	      }
324	      case "file-write": {
325	        const result = await deployFileWrite(
326	          action,
327	          dryRun,
328	          verbose,
329	          home,
330	          planned,
331	        );
332	        if (result.error === null) {
333	          succeeded++;
334	        } else {
335	          failed.push({ action, error: result.error });
336	        }
337	        break;
338	      }
339	      case "config-patch": {
340	        const result = await deployConfigPatch(
341	          action,
342	          dryRun,
343	          verbose,
344	          home,
345	          planned,
346	        );
347	        if (result.error === null) {
348	          succeeded++;
349	        } else {
350	          failed.push({ action, error: result.error });
351	        }
352	        break;
353	      }
354	      default: {
355	        throw new Error(`Unhandled deploy action kind: ${action}`);
356	      }
357	    }
358	  }
359	
360	  return { succeeded, failed, planned };
361	}
