363	async function deploySkillDir(
364	  action: SkillDirDeployAction,
365	  dryRun: boolean,
366	  verbose: boolean,
367	  home: string,
368	  planned: PlannedChange[],
369	): Promise<{ error: string | null }> {
370	  const label = `${action.skill} -> ${action.agent}`;
371	
372	  try {
373	    await access(action.source);
374	  } catch (err) {
375	    const msg = sourceAccessError(err, action.source);
376	    logger.fail(label, msg);
377	    return { error: msg };
378	  }
379	
380	  if (dryRun) {
381	    planned.push({
382	      verb: action.method === "symlink" ? "create-symlink" : "copy-dir",
383	      kind: "skill-dir",
384	      skill: action.skill,
385	      agent: action.agent,
386	      source: action.source,
387	      target: action.target,
388	      method: action.method,
389	      confidence: action.confidence,
390	    });
391	    return { error: null };
392	  }
393	
394	  try {
395	    await executeDeployAction(action, verbose, home);
396	    return { error: null };
397	  } catch (err) {
398	    const msg = err instanceof Error ? err.message : String(err);
399	    logger.fail(label, msg);
400	    return { error: msg };
401	  }
402	}
