404	async function deployFileWrite(
405	  action: FileWriteDeployAction,
406	  dryRun: boolean,
407	  verbose: boolean,
408	  home: string,
409	  planned: PlannedChange[],
410	): Promise<{ error: string | null }> {
411	  const label = `${action.skill} -> ${action.agent}`;
412	
413	  try {
414	    await access(action.source);
415	  } catch (err) {
416	    const msg = sourceAccessError(err, action.source);
417	    logger.fail(label, msg);
418	    return { error: msg };
419	  }
420	
421	  if (dryRun) {
422	    planned.push({
423	      verb: "write-file",
424	      kind: "file-write",
425	      skill: action.skill,
426	      agent: action.agent,
427	      source: action.source,
428	      target: action.target,
429	    });
430	    return { error: null };
431	  }
432	
433	  try {
434	    // Check if target exists — only allow overwrite if we own it
435	    try {
436	      await lstat(action.target);
437	      const isOwned = await verifyDeployment(home, action.target, {
438	        kind: "file-write",
439	        source: action.source,
440	        skill: action.skill,
441	        agent: action.agent,
442	      });
443	      if (!isOwned) {
444	        throw new Error(
445	          `Target "${action.target}" exists but is not managed by inception-engine — refusing to overwrite`,
446	        );
447	      }
448	    } catch (err) {
449	      if (err instanceof Error && err.message.includes("refusing to overwrite"))
450	        throw err;
451	      // ENOENT — target doesn't exist, fine to create
452	    }
453	
454	    await mkdir(path.dirname(action.target), { recursive: true });
455	    await copyFile(action.source, action.target);
456	    await registerDeployment(home, action.target, {
457	      kind: "file-write",
458	      source: action.source,
459	      skill: action.skill,
460	      agent: action.agent,
461	    });
462	    logger.ok(label);
463	    if (verbose) {
464	      logger.detail(`write-file: ${action.source} -> ${action.target}`);
465	    }
466	    return { error: null };
467	  } catch (err) {
468	    const msg = err instanceof Error ? err.message : String(err);
