474	async function deployConfigPatch(
475	  action: ConfigPatchDeployAction,
476	  dryRun: boolean,
477	  verbose: boolean,
478	  home: string,
479	  planned: PlannedChange[],
480	): Promise<{ error: string | null }> {
481	  const label = `${action.skill} -> ${action.agent}`;
482	
483	  if (!isPlainObject(action.patch)) {
484	    const msg = `Config patch for skill "${action.skill}" must be a plain object`;
485	    logger.fail(label, msg);
486	    return { error: msg };
487	  }
488	
489	  const patch = action.patch;
490	
491	  if (dryRun) {
492	    planned.push({
493	      verb: "patch-config",
494	      kind: "config-patch",
495	      skill: action.skill,
496	      agent: action.agent,
497	      target: action.target,
498	      patch,
499	    });
500	    return { error: null };
501	  }
502	
503	  try {
504	    // Guard against double-patching by a different skill/agent
505	    const existingEntry = await lookupDeployment(home, action.target);
506	    if (
507	      existingEntry &&
508	      (existingEntry.skill !== action.skill ||
509	        existingEntry.agent !== action.agent)
510	    ) {
511	      throw new Error(
512	        `Config "${action.target}" is already patched by skill "${existingEntry.skill}" for agent "${existingEntry.agent}" — refusing to double-patch`,
513	      );
514	    }
515	
516	    const original = await readJsonConfig(action.target);
517	    const undoPatch = computeUndoPatch(original, patch);
518	    const patched = applyMergePatch(original, patch);
519	
520	    await writeFile(
521	      action.target,
522	      `${JSON.stringify(patched, null, 2)}\n`,
523	      "utf-8",
524	    );
525	    await registerDeployment(home, action.target, {
526	      kind: "config-patch",
527	      patch,
528	      undoPatch,
529	      skill: action.skill,
530	      agent: action.agent,
531	    });
532	    logger.ok(label);
533	    if (verbose) {
534	      logger.detail(
535	        `patch-config: applied ${Object.keys(patch).length} key(s) to ${action.target}`,
536	      );
537	    }
538	    return { error: null };
539	  } catch (err) {
540	    const msg = err instanceof Error ? err.message : String(err);
541	    logger.fail(label, msg);
542	    return { error: msg };
543	  }
544	}
