546	async function validateSourcePath(
547	  source: string,
548	  skillPath: string,
549	  resolvedSourceDir: string,
550	  realRoot: string,
551	): Promise<void> {
552	  if (!source.startsWith(resolvedSourceDir + path.sep)) {
553	    throw new UserError(
554	      "DEPLOY_FAILED",
555	      `Skill path "${skillPath}" resolves outside the repository root: ${source}`,
556	    );
557	  }
558	
559	  try {
560	    const realSource = await realpath(source);
561	    if (
562	      realSource !== realRoot &&
563	      !realSource.startsWith(realRoot + path.sep)
564	    ) {
565	      throw new UserError(
566	        "DEPLOY_FAILED",
567	        `Skill path "${skillPath}" resolves outside the repository root via symlink: ${source} -> ${realSource}`,
568	      );
569	    }
570	  } catch (err) {
571	    if (err instanceof UserError) throw err;
572	    // Source doesn't exist yet — will be caught during execute
573	  }
574	}
