576	async function validateSkillContract(
577	  source: string,
578	  skillPath: string,
579	): Promise<void> {
580	  let stat: import("node:fs").Stats;
581	  try {
582	    stat = await lstat(source);
583	  } catch (err) {
584	    const code = (err as NodeJS.ErrnoException).code;
585	    if (code === "ENOENT") {
586	      throw new UserError(
587	        "DEPLOY_FAILED",
588	        `Skill "${skillPath}" source not found: ${source}`,
589	      );
590	    }
591	    if (code === "EACCES" || code === "EPERM") {
592	      throw new UserError(
593	        "DEPLOY_FAILED",
594	        `Permission denied accessing skill "${skillPath}" source: ${source}`,
595	      );
596	    }
597	    throw new UserError(
598	      "DEPLOY_FAILED",
599	      `Cannot access skill "${skillPath}" source: ${source}`,
600	    );
601	  }
602	  if (!stat.isDirectory()) {
603	    throw new UserError(
604	      "DEPLOY_FAILED",
605	      `Skill "${skillPath}" source is not a directory: ${source}`,
606	    );
607	  }
608	  try {
609	    await access(path.join(source, "SKILL.md"));
610	  } catch {
611	    throw new UserError(
612	      "DEPLOY_FAILED",
613	      `Skill "${skillPath}" source is missing SKILL.md: ${source}`,
614	    );
615	  }
616	}
