618	async function assertTargetAbsent(targetPath: string): Promise<void> {
619	  try {
620	    await lstat(targetPath);
621	    throw new Error(
622	      `Target path appeared unexpectedly after backup: ${targetPath}`,
623	    );
624	  } catch (err) {
625	    if (err instanceof Error && err.message.startsWith("Target path appeared"))
626	      throw err;
627	    // ENOENT is expected — target should not exist after backup
628	  }
629	}
