631	async function createDeployTarget(
632	  action: SkillDirDeployAction,
633	  home: string,
634	): Promise<void> {
635	  if (action.method === "symlink") {
636	    await symlink(action.source, action.target, "dir");
637	  } else {
638	    await cp(action.source, action.target, { recursive: true });
639	  }
640	  await registerDeployment(home, action.target, {
641	    kind: action.kind,
642	    source: action.source,
643	    skill: action.skill,
644	    agent: action.agent,
645	    method: action.method,
646	  });
647	}
