649	async function executeDeployAction(
650	  action: SkillDirDeployAction,
651	  verbose: boolean,
652	  home: string,
653	): Promise<void> {
654	  const label = `${action.skill} -> ${action.agent}`;
655	  const backupPath = await backupExisting(action.target, verbose, home, {
656	    kind: action.kind,
657	    source: action.source,
658	    skill: action.skill,
659	    agent: action.agent,
660	  });
661	  await mkdir(path.dirname(action.target), { recursive: true });
662	
663	  try {
664	    await assertTargetAbsent(action.target);
665	    await createDeployTarget(action, home);
666	  } catch (createErr) {
667	    if (backupPath) {
668	      try {
669	        await removeTarget(action.target).catch(() => {
670	          /* best-effort cleanup */
671	        });
672	        await rename(backupPath, action.target);
673	      } catch {
674	        // Best-effort rollback
675	      }
676	    }
677	    throw createErr;
678	  }
679	
680	  if (backupPath) {
681	    await removeTarget(backupPath);
682	  }
683	
684	  logger.ok(label);
685	  if (verbose) {
686	    logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
687	  }
688	}
