690	async function backupExisting(
691	  targetPath: string,
692	  verbose: boolean,
693	  home: string,
694	  expected: { kind: string; source: string; skill: string; agent: AgentId },
695	): Promise<string | null> {
696	  try {
697	    await lstat(targetPath);
698	  } catch {
699	    return null;
700	  }
701	
702	  if (
703	    !(await verifyDeployment(home, targetPath, {
704	      kind: "skill-dir",
705	      source: expected.source,
706	      skill: expected.skill,
707	      agent: expected.agent,
708	    }))
709	  ) {
710	    throw new Error(
711	      `Target "${targetPath}" exists but is not managed by inception-engine — refusing to overwrite`,
712	    );
713	  }
714	
715	  const backupPath = `${targetPath}.inception-backup`;
716	
717	  // Clean up any stale backup from a previous failed attempt
718	  try {
719	    await lstat(backupPath);
720	    await removeTarget(backupPath);
721	  } catch {
722	    // No stale backup — expected
723	  }
724	
725	  if (verbose) {
726	    logger.detail(`backing up existing target: ${targetPath}`);
727	  }
728	
729	  await rename(targetPath, backupPath);
730	  return backupPath;
731	}
