733	async function removeTarget(targetPath: string): Promise<void> {
734	  const stat = await lstat(targetPath);
735	  if (stat.isSymbolicLink()) {
736	    await unlink(targetPath);
737	  } else {
738	    await rm(targetPath, { recursive: true });
739	  }
740	}
