  let stat: ...;
  try {
    stat = await lstat(source);
  } catch (err) {
    // handles ENOENT, EACCES/EPERM, generic
  }
  if (!stat.isDirectory()) { ... }
  try {
    await access(path.join(source, "SKILL.md"));
